        }
        --a;--b;--c;
        if(a>=0&&b>=0&&c>=0&&a<N0&&b<N0&&c<N0&&a!=b&&a!=c&&b!=c)
            IN.F.push_back({(int)a,(int)b,(int)c});
    }
    if(IN.V.empty()) return false;
