struct Collapse{Mesh m;vector<unsigned char>VA,FA;vector<double>E;vector<vector<int>>Y;int aliveV=0,aliveF=0;vector<int>A,B;int ta=1,tb=1;double AI,BB,BQ,AJ;bool MID;Collapse(){m=IN;VA.assign(N,1);FA.assign(IN.f.size(),1);E.assign(N,0);Y.assign(N,{});for(int i=0;i<(int)m.f.size();i++){Y[m.f[i].a].push_back(i);Y[m.f[i].b].push_back(i);Y[m.f[i].c].push_back(i);}aliveV=N;aliveF=m.f.size();A.assign(N,0);B.assign(N,0);}bool has(int fid,int v)const{auto&f=m.f[fid];return f.a==v||f.b==v||f.c==v;}int opp(int fid,int u,int v)const{auto&f=m.f[fid];if(f.a!=u&&f.a!=v)return f.a;if(f.b!=u&&f.b!=v)return f.b;return f.c;}array<int,3>s3(int a,int b,int c)const{array<int,3>x{a,b,c};sort(x.begin(),x.end());return x;}bool same(int fid,int a,int b,int c)const{auto&f=m.f[fid];return s3(f.a,f.b,f.c)==s3(a,b,c);}bool edgefaces(int u,int v,int by[2],int op[2])const{int c=0;for(int fid:Y[u])if(FA[fid]&&has(fid,u)&&has(fid,v)){if(c>=2)return false;by[c]=fid;op[c]=opp(fid,u,v);c++;}return c==2&&op[0]>=0&&op[1]>=0&&op[0]!=op[1];}bool link(int u,int v,const int op[2]){if(++ta>2000000000){fill(A.begin(),A.end(),0);ta=1;}if(++tb>2000000000){fill(B.begin(),B.end(),0);tb=1;}for(int fid:Y[u])if(FA[fid]&&has(fid,u)){int x[3]={m.f[fid].a,m.f[fid].b,m.f[fid].c};for(int q:x)if(q!=u&&q!=v)A[q]=ta;}int c=0;for(int fid:Y[v])if(FA[fid]&&has(fid,v)){int x[3]={m.f[fid].a,m.f[fid].b,m.f[fid].c};for(int q:x){if(q==u||q==v)continue;if(A[q]!=ta)continue;if(q!=op[0]&&q!=op[1])return false;if(B[q]!=tb){B[q]=tb;c++;}}}return c==2&&B[op[0]]==tb&&B[op[1]]==tb;}bool dup(int keep,int rem,int fid,int a,int b,int c,int j0,int j1)const{int ix=keep;if(Y[a].size()<Y[ix].size())ix=a;if(Y[b].size()<Y[ix].size())ix=b;if(Y[c].size()<Y[ix].size())ix=c;for(int q:Y[ix]){if(!FA[q]||q==fid||q==j0||q==j1)continue;if(has(q,rem))continue;if(same(q,a,b,c))return true;}return false;}Vec3 gv(int id,int mv,const Vec3&p)const{return id==mv?p:m.v[id];}Vec3 fn(Face f,int mv=-1,Vec3 p={0,0,0})const{return crossp(gv(f.b,mv,p)-gv(f.a,mv,p),gv(f.c